    90→export class NativeLocalProcessExtensionHost implements IExtensionHost {
    91→
    92→	public pid: number | null = null;
    93→	public readonly remoteAuthority = null;
    94→	public extensions: ExtensionHostExtensions | null = null;
    95→
    96→	private readonly _onExit: Emitter<[number, string]> = new Emitter<[number, string]>();
    97→	public readonly onExit: Event<[number, string]> = this._onExit.event;
    98→
    99→	private readonly _onDidSetInspectPort = new Emitter<void>();
   100→
   101→	private readonly _toDispose = new DisposableStore();
   102→
   103→	private readonly _isExtensionDevHost: boolean;
   104→	private readonly _isExtensionDevDebug: boolean;
   105→	private readonly _isExtensionDevDebugBrk: boolean;
   106→	private readonly _isExtensionDevTestFromCli: boolean;
   107→
   108→	// State
   109→	private _terminating: boolean;
   110→
   111→	// Resources, in order they get acquired/created when .start() is called:
   112→	private _inspectListener: { port: number; host: string } | null;
   113→	private _extensionHostProcess: ExtensionHostProcess | null;
   114→	private _messageProtocol: Promise<IMessagePassingProtocol> | null;
   115→
   116→	constructor(
   117→		public readonly runningLocation: LocalProcessRunningLocation,
   118→		public readonly startup: ExtensionHostStartup.EagerAutoStart | ExtensionHostStartup.EagerManualStart,
   119→		private readonly _initDataProvider: ILocalProcessExtensionHostDataProvider,
   120→		@IWorkspaceContextService private readonly _contextService: IWorkspaceContextService,
   121→		@INotificationService private readonly _notificationService: INotificationService,
   122→		@INativeHostService private readonly _nativeHostService: INativeHostService,
   123→		@ILifecycleService private readonly _lifecycleService: ILifecycleService,
   124→		@INativeWorkbenchEnvironmentService private readonly _environmentService: INativeWorkbenchEnvironmentService,
   125→		@IUserDataProfilesService private readonly _userDataProfilesService: IUserDataProfilesService,
   126→		@ITelemetryService private readonly _telemetryService: ITelemetryService,
   127→		@ILogService private readonly _logService: ILogService,
   128→		@ILoggerService private readonly _loggerService: ILoggerService,
   129→		@ILabelService private readonly _labelService: ILabelService,
   130→		@IExtensionHostDebugService private readonly _extensionHostDebugService: IExtensionHostDebugService,
   131→		@IHostService private readonly _hostService: IHostService,
   132→		@IProductService private readonly _productService: IProductService,
   133→		@IShellEnvironmentService private readonly _shellEnvironmentService: IShellEnvironmentService,
   134→		@IExtensionHostStarter private readonly _extensionHostStarter: IExtensionHostStarter,
   135→	) {
   136→		const devOpts = parseExtensionDevOptions(this._environmentService);
   137→		this._isExtensionDevHost = devOpts.isExtensionDevHost;
   138→		this._isExtensionDevDebug = devOpts.isExtensionDevDebug;
   139→		this._isExtensionDevDebugBrk = devOpts.isExtensionDevDebugBrk;
   140→		this._isExtensionDevTestFromCli = devOpts.isExtensionDevTestFromCli;
   141→
   142→		this._terminating = false;
   143→
   144→		this._inspectListener = null;
   145→		this._extensionHostProcess = null;
   146→		this._messageProtocol = null;
   147→
   148→		this._toDispose.add(this._onExit);
   149→		this._toDispose.add(this._lifecycleService.onWillShutdown(e => this._onWillShutdown(e)));
   150→		this._toDispose.add(this._extensionHostDebugService.onClose(event => {
   151→			if (this._isExtensionDevHost && this._environmentService.debugExtensionHost.debugId === event.sessionId) {
   152→				this._nativeHostService.closeWindow();
   153→			}
   154→		}));
   155→		this._toDispose.add(this._extensionHostDebugService.onReload(event => {
   156→			if (this._isExtensionDevHost && this._environmentService.debugExtensionHost.debugId === event.sessionId) {
   157→				this._hostService.reload();
   158→			}
   159→		}));
   160→	}
   161→
   162→	public dispose(): void {
   163→		if (this._terminating) {
   164→			return;
   165→		}
   166→		this._terminating = true;
   167→
   168→		this._toDispose.dispose();
   169→	}
   170→
   171→	public start(): Promise<IMessagePassingProtocol> {
   172→		if (this._terminating) {
   173→			// .terminate() was called
   174→			throw new CancellationError();
   175→		}
   176→
   177→		if (!this._messageProtocol) {
   178→			this._messageProtocol = this._start();
   179→		}
   180→
   181→		return this._messageProtocol;
   182→	}
   183→
   184→	private async _start(): Promise<IMessagePassingProtocol> {
   185→		const [extensionHostCreationResult, portNumber, processEnv] = await Promise.all([
   186→			this._extensionHostStarter.createExtensionHost(),
   187→			this._tryFindDebugPort(),
   188→			this._shellEnvironmentService.getShellEnv(),
   189→		]);
   190→
   191→		this._extensionHostProcess = new ExtensionHostProcess(extensionHostCreationResult.id, this._extensionHostStarter);
   192→
   193→		const env = objects.mixin(processEnv, {
   194→			VSCODE_ESM_ENTRYPOINT: 'vs/workbench/api/node/extensionHostProcess',
   195→			VSCODE_HANDLES_UNCAUGHT_ERRORS: true
   196→		});
   197→
   198→		if (this._environmentService.debugExtensionHost.env) {
   199→			objects.mixin(env, this._environmentService.debugExtensionHost.env);
   200→		}
   201→
   202→		removeDangerousEnvVariables(env);
   203→
   204→		if (this._isExtensionDevHost) {
   205→			// Unset `VSCODE_CODE_CACHE_PATH` when developing extensions because it might
   206→			// be that dependencies, that otherwise would be cached, get modified.
   207→			delete env['VSCODE_CODE_CACHE_PATH'];
   208→		}
   209→
   210→		const opts: IExtensionHostProcessOptions = {
   211→			responseWindowId: this._nativeHostService.windowId,
   212→			responseChannel: 'vscode:startExtensionHostMessagePortResult',
   213→			responseNonce: generateUuid(),
   214→			env,
   215→			// We only detach the extension host on windows. Linux and Mac orphan by default
   216→			// and detach under Linux and Mac create another process group.
   217→			// We detach because we have noticed that when the renderer exits, its child processes
   218→			// (i.e. extension host) are taken down in a brutal fashion by the OS
   219→			detached: !!platform.isWindows,
   220→			execArgv: undefined as string[] | undefined,
   221→			silent: true
   222→		};
   223→
   224→		const inspectHost = '127.0.0.1';
   225→		if (portNumber !== 0) {
   226→			opts.execArgv = [
   227→				'--nolazy',
   228→				(this._isExtensionDevDebugBrk ? '--inspect-brk=' : '--inspect=') + `${inspectHost}:${portNumber}`
   229→			];
   230→		} else {
   231→			opts.execArgv = ['--inspect-port=0'];
   232→		}
   233→
   234→		if (this._environmentService.extensionTestsLocationURI) {
   235→			opts.execArgv.unshift('--expose-gc');
   236→		}
   237→
   238→		if (this._environmentService.args['prof-v8-extensions']) {
   239→			opts.execArgv.unshift('--prof');
   240→		}
   241→
   242→		// Refs https://github.com/microsoft/vscode/issues/189805
   243→		opts.execArgv.unshift('--dns-result-order=ipv4first');
   244→
   245→		// Catch all output coming from the extension host process
   246→		type Output = { data: string; format: string[] };
   247→		const onStdout = this._handleProcessOutputStream(this._extensionHostProcess.onStdout, this._toDispose);
   248→		const onStderr = this._handleProcessOutputStream(this._extensionHostProcess.onStderr, this._toDispose);
   249→		const onOutput = Event.any(
   250→			Event.map(onStdout.event, o => ({ data: `%c${o}`, format: [''] })),
   251→			Event.map(onStderr.event, o => ({ data: `%c${o}`, format: ['color: red'] }))
   252→		);
   253→
   254→		// Debounce all output, so we can render it in the Chrome console as a group
   255→		const onDebouncedOutput = Event.debounce<Output>(onOutput, (r, o) => {
   256→			return r
   257→				? { data: r.data + o.data, format: [...r.format, ...o.format] }
   258→				: { data: o.data, format: o.format };
   259→		}, 100);
   260→
   261→		// Print out extension host output
   262→		this._toDispose.add(onDebouncedOutput(output => {
   263→			const inspectorUrlMatch = output.data && output.data.match(/ws:\/\/([^\s]+):(\d+)\/[^\s]+/);
   264→			if (inspectorUrlMatch) {
   265→				const [, host, port] = inspectorUrlMatch;
   266→				if (!this._environmentService.isBuilt && !this._isExtensionDevTestFromCli) {
   267→					console.log(`%c[Extension Host] %cdebugger inspector at devtools://devtools/bundled/inspector.html?experiments=true&v8only=true&ws=${inspectorUrlMatch[1]}`, 'color: blue', 'color:');
   268→				}
   269→				if (!this._inspectListener) {
   270→					this._inspectListener = { host, port: Number(port) };
   271→					this._onDidSetInspectPort.fire();
   272→				}
   273→			} else {
   274→				if (!this._isExtensionDevTestFromCli) {
   275→					console.group('Extension Host');
   276→					console.log(output.data, ...output.format);
   277→					console.groupEnd();
   278→				}
   279→			}
   280→		}));
   281→
   282→		// Lifecycle
   283→
   284→		this._toDispose.add(this._extensionHostProcess.onExit(({ code, signal }) => this._onExtHostProcessExit(code, signal)));
   285→
   286→		// Notify debugger that we are ready to attach to the process if we run a development extension
   287→		if (portNumber) {
   288→			if (this._isExtensionDevHost && this._isExtensionDevDebug && this._environmentService.debugExtensionHost.debugId) {
   289→				this._extensionHostDebugService.attachSession(this._environmentService.debugExtensionHost.debugId, portNumber);
   290→			}
   291→			this._inspectListener = { port: portNumber, host: inspectHost };
   292→			this._onDidSetInspectPort.fire();
   293→		}
   294→
   295→		// Help in case we fail to start it
   296→		let startupTimeoutHandle: any;
   297→		if (!this._environmentService.isBuilt && !this._environmentService.remoteAuthority || this._isExtensionDevHost) {
   298→			startupTimeoutHandle = setTimeout(() => {
   299→				this._logService.error(`[LocalProcessExtensionHost]: Extension host did not start in 10 seconds (debugBrk: ${this._isExtensionDevDebugBrk})`);
   300→
   301→				const msg = this._isExtensionDevDebugBrk
   302→					? nls.localize('extensionHost.startupFailDebug', "Extension host did not start in 10 seconds, it might be stopped on the first line and needs a debugger to continue.")
   303→					: nls.localize('extensionHost.startupFail', "Extension host did not start in 10 seconds, that might be a problem.");
   304→
   305→				this._notificationService.prompt(Severity.Warning, msg,
   306→					[{
   307→						label: nls.localize('reloadWindow', "Reload Window"),
   308→						run: () => this._hostService.reload()
   309→					}],
   310→					{
   311→						sticky: true,
   312→						priority: NotificationPriority.URGENT
   313→					}
   314→				);
   315→			}, 10000);
   316→		}
   317→
   318→		// Initialize extension host process with hand shakes
   319→		const protocol = await this._establishProtocol(this._extensionHostProcess, opts);
   320→		await this._performHandshake(protocol);
   321→		clearTimeout(startupTimeoutHandle);
   322→		return protocol;
   323→	}
   324→
   325→	/**
   326→	 * Find a free port if extension host debugging is enabled.
   327→	 */
   328→	private async _tryFindDebugPort(): Promise<number> {
   329→
   330→		if (typeof this._environmentService.debugExtensionHost.port !== 'number') {
   331→			return 0;
   332→		}
   333→
   334→		const expected = this._environmentService.debugExtensionHost.port;
   335→		const port = await this._nativeHostService.findFreePort(expected, 10 /* try 10 ports */, 5000 /* try up to 5 seconds */, 2048 /* skip 2048 ports between attempts */);
   336→
   337→		if (!this._isExtensionDevTestFromCli) {
   338→			if (!port) {
   339→				console.warn('%c[Extension Host] %cCould not find a free port for debugging', 'color: blue', 'color:');
   340→			} else {
   341→				if (port !== expected) {
   342→					console.warn(`%c[Extension Host] %cProvided debugging port ${expected} is not free, using ${port} instead.`, 'color: blue', 'color:');
   343→				}
   344→				if (this._isExtensionDevDebugBrk) {
   345→					console.warn(`%c[Extension Host] %cSTOPPED on first line for debugging on port ${port}`, 'color: blue', 'color:');
   346→				} else {
   347→					console.info(`%c[Extension Host] %cdebugger listening on port ${port}`, 'color: blue', 'color:');
   348→				}
   349→			}
   350→		}
   351→
   352→		return port || 0;
   353→	}
   354→
   355→	private _establishProtocol(extensionHostProcess: ExtensionHostProcess, opts: IExtensionHostProcessOptions): Promise<IMessagePassingProtocol> {
   356→
   357→		writeExtHostConnection(new MessagePortExtHostConnection(), opts.env);
   358→
   359→		// Get ready to acquire the message port from the shared process worker
   360→		const portPromise = acquirePort(undefined /* we trigger the request via service call! */, opts.responseChannel, opts.responseNonce);
   361→
   362→		return new Promise<IMessagePassingProtocol>((resolve, reject) => {
   363→
   364→			const handle = setTimeout(() => {
   365→				reject('The local extension host took longer than 60s to connect.');
   366→			}, 60 * 1000);
   367→
   368→			portPromise.then((port) => {
   369→				this._toDispose.add(toDisposable(() => {
   370→					// Close the message port when the extension host is disposed
   371→					port.close();
   372→				}));
   373→				clearTimeout(handle);
   374→
   375→				const onMessage = new BufferedEmitter<VSBuffer>();
   376→				port.onmessage = ((e) => {
   377→					if (e.data) {
   378→						onMessage.fire(VSBuffer.wrap(e.data));
   379→					}
   380→				});
   381→				port.start();
   382→
   383→				resolve({
   384→					onMessage: onMessage.event,
   385→					send: message => port.postMessage(message.buffer),
   386→				});
   387→			});
   388→
   389→			// Now that the message port listener is installed, start the ext host process
   390→			const sw = StopWatch.create(false);
   391→			extensionHostProcess.start(opts).then(({ pid }) => {
   392→				if (pid) {
   393→					this.pid = pid;
   394→				}
   395→				this._logService.info(`Started local extension host with pid ${pid}.`);
   396→				const duration = sw.elapsed();
   397→				if (platform.isCI) {
   398→					this._logService.info(`IExtensionHostStarter.start() took ${duration} ms.`);
   399→				}
   400→			}, (err) => {
   401→				// Starting the ext host process resulted in an error
   402→				reject(err);
   403→			});
   404→		});
   405→	}
   406→
   407→	private _performHandshake(protocol: IMessagePassingProtocol): Promise<void> {
   408→		// 1) wait for the incoming `ready` event and send the initialization data.
   409→		// 2) wait for the incoming `initialized` event.
   410→		return new Promise<void>((resolve, reject) => {
   411→
   412→			let timeoutHandle: any;
   413→			const installTimeoutCheck = () => {
   414→				timeoutHandle = setTimeout(() => {
   415→					reject('The local extension host took longer than 60s to send its ready message.');
   416→				}, 60 * 1000);
   417→			};
   418→			const uninstallTimeoutCheck = () => {
   419→				clearTimeout(timeoutHandle);
   420→			};
   421→
   422→			// Wait 60s for the ready message
   423→			installTimeoutCheck();
   424→
   425→			const disposable = protocol.onMessage(msg => {
   426→
   427→				if (isMessageOfType(msg, MessageType.Ready)) {
   428→
   429→					// 1) Extension Host is ready to receive messages, initialize it
   430→					uninstallTimeoutCheck();
   431→
   432→					this._createExtHostInitData().then(data => {
   433→
   434→						// Wait 60s for the initialized message
   435→						installTimeoutCheck();
   436→
   437→						protocol.send(VSBuffer.fromString(JSON.stringify(data)));
   438→					});
   439→					return;
   440→				}
   441→
   442→				if (isMessageOfType(msg, MessageType.Initialized)) {
   443→
   444→					// 2) Extension Host is initialized
   445→					uninstallTimeoutCheck();
   446→
   447→					// stop listening for messages here
   448→					disposable.dispose();
   449→
   450→					// release this promise
   451→					resolve();
   452→					return;
   453→				}
   454→
   455→				console.error(`received unexpected message during handshake phase from the extension host: `, msg);
   456→			});
   457→
   458→		});
   459→	}
   460→
   461→	private async _createExtHostInitData(): Promise<IExtensionHostInitData> {
   462→		const initData = await this._initDataProvider.getInitData();
   463→		this.extensions = initData.extensions;
   464→		const workspace = this._contextService.getWorkspace();
   465→		return {
   466→			commit: this._productService.commit,
   467→			version: this._productService.version,
   468→			quality: this._productService.quality,
   469→			parentPid: 0,
   470→			environment: {
   471→				isExtensionDevelopmentDebug: this._isExtensionDevDebug,
   472→				appRoot: this._environmentService.appRoot ? URI.file(this._environmentService.appRoot) : undefined,
   473→				appName: this._productService.nameLong,
   474→				appHost: this._productService.embedderIdentifier || 'desktop',
   475→				appUriScheme: this._productService.urlProtocol,
   476→				isExtensionTelemetryLoggingOnly: isLoggingOnly(this._productService, this._environmentService),
   477→				appLanguage: platform.language,
   478→				extensionDevelopmentLocationURI: this._environmentService.extensionDevelopmentLocationURI,
   479→				extensionTestsLocationURI: this._environmentService.extensionTestsLocationURI,
   480→				globalStorageHome: this._userDataProfilesService.defaultProfile.globalStorageHome,
   481→				workspaceStorageHome: this._environmentService.workspaceStorageHome,
   482→				extensionLogLevel: this._environmentService.extensionLogLevel
   483→			},
   484→			workspace: this._contextService.getWorkbenchState() === WorkbenchState.EMPTY ? undefined : {
   485→				configuration: workspace.configuration ?? undefined,
   486→				id: workspace.id,
   487→				name: this._labelService.getWorkspaceLabel(workspace),
   488→				isUntitled: workspace.configuration ? isUntitledWorkspace(workspace.configuration, this._environmentService) : false,
   489→				transient: workspace.transient
   490→			},
   491→			remote: {
   492→				authority: this._environmentService.remoteAuthority,
   493→				connectionData: null,
   494→				isRemote: false
   495→			},
   496→			consoleForward: {
   497→				includeStack: !this._isExtensionDevTestFromCli && (this._isExtensionDevHost || !this._environmentService.isBuilt || this._productService.quality !== 'stable' || this._environmentService.verbose),
   498→				logNative: !this._isExtensionDevTestFromCli && this._isExtensionDevHost
   499→			},
   500→			extensions: this.extensions.toSnapshot(),
   501→			telemetryInfo: {
   502→				sessionId: this._telemetryService.sessionId,
