   262→		// Apply supported environment variables from config
   263→		env['VSCODE_ESM_ENTRYPOINT'] = configuration.entryPoint;
   264→		if (typeof configuration.parentLifecycleBound === 'number') {
   265→			env['VSCODE_PARENT_PID'] = String(configuration.parentLifecycleBound);
