   488→export class WindowUtilityProcess extends UtilityProcess {
   489→
   490→	constructor(
   491→		@ILogService logService: ILogService,
   492→		@IWindowsMainService private readonly windowsMainService: IWindowsMainService,
   493→		@ITelemetryService telemetryService: ITelemetryService,
   494→		@ILifecycleMainService lifecycleMainService: ILifecycleMainService
   495→	) {
   496→		super(logService, telemetryService, lifecycleMainService);
   497→	}
   498→
   499→	override start(configuration: IWindowUtilityProcessConfiguration): boolean {
   500→		const responseWindow = this.windowsMainService.getWindowById(configuration.responseWindowId);
   501→		if (!responseWindow?.win || responseWindow.win.isDestroyed() || responseWindow.win.webContents.isDestroyed()) {
   502→			this.log('Refusing to start utility process because requesting window cannot be found or is destroyed...', Severity.Error);
   503→
   504→			return true;
   505→		}
   506→
   507→		// Start utility process
   508→		const started = super.doStart(configuration);
   509→		if (!started) {
   510→			return false;
   511→		}
   512→
   513→		// Register to window events
   514→		this.registerWindowListeners(responseWindow.win, configuration);
   515→
   516→		// Establish & exchange message ports
   517→		const windowPort = this.connect(configuration.payload);
   518→		responseWindow.win.webContents.postMessage(configuration.responseChannel, configuration.responseNonce, [windowPort]);
   519→
   520→		return true;
   521→	}
   522→
   523→	private registerWindowListeners(window: BrowserWindow, configuration: IWindowUtilityProcessConfiguration): void {
   524→
   525→		// If the lifecycle of the utility process is bound to the window,
   526→		// we kill the process if the window closes or changes
   527→
   528→		if (configuration.windowLifecycleBound) {
   529→			this._register(Event.filter(this.lifecycleMainService.onWillLoadWindow, e => e.window.win === window)(() => this.kill()));
   530→			this._register(Event.fromNodeEventEmitter(window, 'closed')(() => this.kill()));
   531→		}
   532→	}
   533→}
